// Cargo.toml: [dev-dependencies] proptest = "1"

fn reverse(s: &str) -> String {
    s.chars().rev().collect()
}

fn sort_vec(mut v: Vec<i32>) -> Vec<i32> {
    v.sort();
    v
}

#[cfg(test)]
mod tests {
    use super::*;
    use proptest::prelude::*;

    proptest! {
        // Reversing twice gives back the original
        #[test]
        fn test_double_reverse(s in ".*") {
            assert_eq!(reverse(&reverse(&s)), s);
        }

        // Reversed string has the same length
        #[test]
        fn test_reverse_length(s in "[a-zA-Z0-9 ]{0,100}") {
            assert_eq!(reverse(&s).len(), s.len());
        }

        // Sorted output has same length as input
        #[test]
        fn test_sort_preserves_length(v in prop::collection::vec(-1000..1000i32, 0..100)) {
            let sorted = sort_vec(v.clone());
            assert_eq!(sorted.len(), v.len());
        }

        // Sorted output is actually sorted
        #[test]
        fn test_sort_is_sorted(v in prop::collection::vec(-1000..1000i32, 0..100)) {
            let sorted = sort_vec(v);
            for window in sorted.windows(2) {
                assert!(window[0] <= window[1]);
            }
        }

        // Sorted output contains the same elements
        #[test]
        fn test_sort_preserves_elements(v in prop::collection::vec(-100..100i32, 0..50)) {
            let mut expected = v.clone();
            expected.sort();
            assert_eq!(sort_vec(v), expected);
        }
    }
}

use proptest::prelude::*;

#[derive(Debug, Clone)]
struct Money {
    cents: u64,
}

impl Money {
    fn new(cents: u64) -> Self {
        Money { cents }
    }

    fn add(&self, other: &Money) -> Money {
        Money { cents: self.cents + other.cents }
    }
}

prop_compose! {
    fn money_strategy()(cents in 0..1_000_000u64) -> Money {
        Money::new(cents)
    }
}

proptest! {
    #[test]
    fn test_addition_is_commutative(
        a in money_strategy(),
        b in money_strategy()
    ) {
        assert_eq!(a.add(&b).cents, b.add(&a).cents);
    }

    #[test]
    fn test_addition_is_associative(
        a in money_strategy(),
        b in money_strategy(),
        c in money_strategy()
    ) {
        let left = a.add(&b).add(&c);
        let right = a.add(&b.add(&c));
        assert_eq!(left.cents, right.cents);
    }
}
